"use client";

import { useState, useMemo } from "react";
import Link from "next/link";
import { Header } from "@/components/Header";
import { CategoryFilter } from "@/components/CategoryFilter";
import { HookGrid } from "@/components/HookGrid";
import { getAllHooks, filterHooks } from "@/lib/hooks";
import { HookCategory } from "@/types/hook";

export default function BrowsePage() {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState<HookCategory | "all">("all");

  const allHooks = getAllHooks();
  const filteredHooks = useMemo(
    () => filterHooks(allHooks, searchQuery, selectedCategory),
    [allHooks, searchQuery, selectedCategory]
  );

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="mb-8">
          <Link href="/" className="text-blue-600 hover:underline mb-4 inline-block">
            ← Back to Home
          </Link>
          <Header searchQuery={searchQuery} onSearchChange={setSearchQuery} />
        </div>

        <div className="mb-8">
          <CategoryFilter selected={selectedCategory} onSelect={setSelectedCategory} />
        </div>

        <div className="mb-4 text-sm text-gray-500 dark:text-gray-400">
          Showing {filteredHooks.length} of {allHooks.length} hooks
        </div>

        <HookGrid hooks={filteredHooks} />
      </div>
    </div>
  );
}
